package jsbench;

import io.roastedroot.quickjs4j.core.Engine;
import io.roastedroot.quickjs4j.core.Runner;

/**
 * Backend 4: QuickJs4J — QuickJS compiled to wasm, hosted by Chicory's
 * build-time AOT compiler. Pulled transitively via the
 * `io.roastedroot:quickjs4j` artifact (no Chicory dependency to manage
 * directly). Output is wired through a typed `@Invokables` interface
 * (`SieveApi`) whose companion `SieveApi_Invokables` class is generated by
 * the `quickjs4j-processor` annotation processor at compile time.
 */
public final class QuickJs4JBackend implements JsBackend {
    private final Runner runner;
    private final SieveApi api;

    public QuickJs4JBackend() {
        Engine engine = Engine.builder()
                .addInvokables(SieveApi_Invokables.toInvokables())
                .build();
        this.runner = Runner.builder().withEngine(engine).build();
        this.api = SieveApi_Invokables.create(Workload.INSTANCE.getSieveSource(), runner);
    }

    @Override public String getName() { return "quickjs4j"; }
    @Override public int sieve(int n) { return api.sieve(n); }
    @Override public void close() { runner.close(); }
}
